"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[378],{728:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new Controller for the given GUI instance.","params":[{"name":"gui","desc":"The GUI instance to manage","lua_type":"ScreenGui | SurfaceGui | BillboardGui"}],"returns":[{"desc":"A new Controller for the given GUI instance","lua_type":"Controller"}],"function_type":"static","source":{"line":159,"path":"src/Flux/Controller.luau"}},{"name":"Unmount","desc":"Destroys the GUI `Instance` and disconnects all bindings. This should be called when you\\nare finished with the GUI to properly clean up resources and prevent memory leaks.\\n\\n```lua\\nlocal controller = Flux:MountScreenGui(gui)\\ncontroller:Unmount() -- Clean up when done\\n```","params":[{"name":"self","desc":"","lua_type":"Self"}],"returns":[],"function_type":"static","source":{"line":184,"path":"src/Flux/Controller.luau"}},{"name":"Destroy","desc":"Compatibility alias for `Unmount`. Calling `Destroy` and `Unmount` has identical behavior.","params":[{"name":"self","desc":"","lua_type":"Self"}],"returns":[],"function_type":"static","source":{"line":192,"path":"src/Flux/Controller.luau"}},{"name":"GetInstance","desc":"Returns the GUI instance managed by this controller.\\n\\n```lua\\nlocal gui = controller:GetInstance()\\nlocal frame = gui:FindFirstChild(\\"Frame\\")\\n```","params":[{"name":"self","desc":"","lua_type":"Self"}],"returns":[{"desc":"The managed GUI instance","lua_type":"ScreenGui | SurfaceGui | BillboardGui"}],"function_type":"static","source":{"line":206,"path":"src/Flux/Controller.luau"}},{"name":"Bind","desc":"Binds to a `State` object so that `callback` fires immediately with the current value,\\nand then again every time the state changes. The binding is automatically cleaned up when\\nthe controller is unmounted.\\n\\n```lua\\nlocal coins: Flux.State<number> = Flux:State(0)\\ncontroller:Bind(coins, function(count: number)\\n\\tlocal label = controller:GetInstance():FindFirstChild(\\"CoinsLabel\\")\\n\\tif label and label:IsA(\\"TextLabel\\") then\\n\\t\\tlabel.Text = tostring(count)\\n\\tend\\nend)\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"state","desc":"The reactive state to observe","lua_type":"State<T>"},{"name":"callback","desc":"Function to call with the current and future values","lua_type":"(newValue: T?) -> ()"}],"returns":[],"function_type":"static","source":{"line":228,"path":"src/Flux/Controller.luau"}},{"name":"BindProperty","desc":"Binds a `State` directly to a named property on an instance. The property is updated immediately\\nwith the current state value and then again every time the state changes.\\n\\n```lua\\nlocal size = Flux:State(UDim2.fromScale(0.5, 0.5))\\ncontroller:BindProperty(size, frame, \\"Size\\")\\nsize:Set(UDim2.fromScale(1, 1)) -- frame.Size updates automatically\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"state","desc":"The reactive state to observe","lua_type":"State<T>"},{"name":"instance","desc":"The GUI instance to update","lua_type":"Instance"},{"name":"property","desc":"The name of the property to bind to","lua_type":"string"}],"returns":[],"function_type":"static","source":{"line":251,"path":"src/Flux/Controller.luau"}},{"name":"OnEvent","desc":"Connects to a named event on an instance with automatic cleanup. The connection is automatically\\ndisconnected when the controller is unmounted.\\n\\n```lua\\nlocal button = controller:GetInstance():FindFirstChild(\\"Button\\")\\nif button then\\n\\tcontroller:OnEvent(button, \\"Activated\\", function()\\n\\t\\tprint(\\"Button clicked!\\")\\n\\tend)\\nend\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"instance","desc":"The GUI instance whose event to connect to","lua_type":"Instance"},{"name":"eventName","desc":"The name of the event (e.g. \\"Activated\\", \\"MouseEnter\\")","lua_type":"string"},{"name":"callback","desc":"Function to call when the event fires","lua_type":"(...any) -> ()"}],"returns":[],"function_type":"static","source":{"line":278,"path":"src/Flux/Controller.luau"}},{"name":"Mount","desc":"Applies a reusable `Component` function to a child instance. The component receives a `Scope`\\nthat allows it to bind to reactive state. All bindings made by the component are automatically\\ncleaned up when the controller is unmounted.\\n\\n\\n```lua\\nlocal function HealthBar(instance: Instance, scope: Flux.Scope, properties: {health: Flux.State<number>})\\n\\tscope:Bind(properties.health, function(hp: number)\\n\\t\\tlocal bar: Frame = instance :: Frame\\n\\t\\tbar.Size = UDim2.fromScale(hp / 100, 1)\\n\\tend)\\nend\\n\\nlocal healthState = Flux:State(100)\\nlocal healthBarFrame = controller:GetInstance():FindFirstChild(\\"HealthBarFrame\\")\\nif healthBarFrame then\\n\\tcontroller:Mount(HealthBar, healthBarFrame, {health = healthState})\\nend\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"component","desc":"The component function to apply","lua_type":"Component"},{"name":"instance","desc":"The GUI instance to pass to the component","lua_type":"Instance"},{"name":"properties","desc":"Optional properties table to pass to the component","lua_type":"{[string]: any}?"}],"returns":[],"function_type":"static","source":{"line":312,"path":"src/Flux/Controller.luau"}},{"name":"MountWhen","desc":"Conditionally mounts a component based on a boolean state. When the condition becomes `true`,\\nthe component is mounted and receives its own scope. When it becomes `false`, the component\\nand all its bindings are cleaned up. If the condition becomes `true` again, the component is\\nmounted again with a fresh scope (it does not resume prior local state). The target `instance`\\nremains in the hierarchy; only component behavior is mounted/unmounted. Only one mounted\\ncomponent scope is active at a time.\\n\\n```lua\\nlocal isVisible = Flux:State(false)\\nlocal function Panel(instance: Instance, scope: Flux.Scope)\\n\\tlocal text = Flux:State(\\"Hello\\")\\n\\tscope:BindProperty(text, instance, \\"Text\\")\\nend\\nlocal panelFrame = controller:GetInstance():FindFirstChild(\\"Panel\\")\\nif panelFrame then\\n\\tcontroller:MountWhen(isVisible, Panel, panelFrame)\\nend\\nisVisible:Set(true) -- Component mounts\\nisVisible:Set(false) -- Component unmounts\\n```","params":[{"name":"self","desc":"","lua_type":"Self"},{"name":"condition","desc":"A boolean state that drives visibility","lua_type":"State<boolean>"},{"name":"component","desc":"The component function to conditionally mount","lua_type":"Component"},{"name":"instance","desc":"The GUI instance to pass to the component","lua_type":"Instance"},{"name":"properties","desc":"Optional properties table to pass to the component","lua_type":"{[string]: any}?"}],"returns":[],"function_type":"static","source":{"line":349,"path":"src/Flux/Controller.luau"}}],"properties":[],"types":[{"name":"Scope","desc":"A lifecycle scope passed to each component function. Use `Bind` to subscribe to reactive state,\\n`BindProperty` to drive a named instance property directly from state, `OnEvent` to connect instance\\nevents, `Mount` to compose child components, and `MountWhen` for conditional rendering.\\nAll bindings, event connections, and child mounts made through this scope are automatically cleaned\\nup when the parent GUI is unmounted.","fields":[{"name":"Bind","lua_type":"(self, state: State<T>, callback: (newValue: T?) -> ()) -> ()","desc":"Binds to a `State` scoped to this component\'s lifecycle"},{"name":"BindProperty","lua_type":"(self, state: State<T>, instance: Instance, property: string) -> ()","desc":"Binds a `State` directly to a named property on an instance"},{"name":"OnEvent","lua_type":"(self, instance: Instance, eventName: string, callback: (...any) -> ()) -> ()","desc":"Connects an instance event scoped to this component\'s lifecycle"},{"name":"Mount","lua_type":"(self, component: Component, instance: Instance, properties: {[string]: any}?) -> ()","desc":"Mounts a child component scoped to this component\'s lifecycle"},{"name":"MountWhen","lua_type":"(self, condition: State<boolean>, component: Component, instance: Instance, properties: {[string]: any}?) -> ()","desc":"Conditionally mounts a child component based on state"}],"source":{"line":19,"path":"src/Flux/Controller.luau"}},{"name":"Component","desc":"A reusable function that applies behavior to a GUI child `Instance`. Components are mounted to a specific\\n`Instance` in the GUI hierarchy and can bind to reactive state using the provided `Scope`. Components\\nshould be used for reusable pieces of UI behavior. For example, you might have a \\"HealthBar\\" component that\\nyou mount to any Frame to turn it into a health bar, or a \\"Draggable\\" component that makes a GUI element\\ndraggable. Components should not manage the lifecycle of their own `Instance` (i.e. by destroying it or\\nreparenting it), they should only be responsible for updating the instance\'s properties in response to state changes,\\npassed down through `properties` or observed via `Bind`. Let the parent `Controller` manage the lifecycle of all instances.","lua_type":"(instance: Instance, scope: Scope, properties: {[string]: any}?) -> ()","source":{"line":39,"path":"src/Flux/Controller.luau"}},{"name":"State","desc":"A reactive state object. Create these using `Flux:State` and pass them to\\n`Controller:Bind` or `Scope:Bind` inside components to reactively drive UI updates.","source":{"line":48,"path":"src/Flux/Controller.luau"}},{"name":"Self","desc":"","lua_type":"Controller","source":{"line":69,"path":"src/Flux/Controller.luau"}}],"name":"Controller","desc":"Controller for a mounted GUI. Returned by every `Mount` method call. A `Controller` manages the lifecycle of\\nthe GUI `Instance` and all reactive connections. Call `Unmount` to clean up, `Bind` to react to state changes,\\nand `Mount` to apply reusable components that are automatically cleaned up when the controller is unmounted.\\n`Destroy` is provided as an alias of `Unmount` for compatibility with APIs that expect `:Destroy()`.\\nAccess the GUI hierarchy via `GetInstance()`.","source":{"line":80,"path":"src/Flux/Controller.luau"}}')}}]);